-- Create schema for Elevate OS\n\n-- Enable UUID extension\nCREATE EXTENSION IF NOT EXISTS \"uuid-ossp\";\n\n-- Profiles table\nCREATE TABLE IF NOT EXISTS profiles (\n  id UUID REFERENCES auth.users(id) ON DELETE CASCADE PRIMARY KEY,\n  email TEXT NOT NULL UNIQUE,\n  name TEXT NOT NULL,\n  avatar_url TEXT,\n  role TEXT DEFAULT 'user' CHECK (role IN ('admin', 'manager', 'user')),\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Niches table\nCREATE TABLE IF NOT EXISTS niches (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  name TEXT NOT NULL UNIQUE,\n  description TEXT,\n  icon TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Services table\nCREATE TABLE IF NOT EXISTS services (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  name TEXT NOT NULL,\n  description TEXT,\n  price DECIMAL(10, 2) NOT NULL,\n  niche_id UUID REFERENCES niches(id) ON DELETE CASCADE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Leads table\nCREATE TABLE IF NOT EXISTS leads (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  name TEXT NOT NULL,\n  email TEXT,\n  phone TEXT,\n  company TEXT,\n  niche TEXT,\n  status TEXT DEFAULT 'prospect' CHECK (status IN ('prospect', 'contacted', 'qualified', 'proposal_sent', 'negotiation', 'won', 'lost')),\n  value DECIMAL(10, 2),\n  notes TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Copies table\nCREATE TABLE IF NOT EXISTS copies (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  title TEXT NOT NULL,\n  content TEXT NOT NULL,\n  niche TEXT,\n  type TEXT DEFAULT 'initial' CHECK (type IN ('initial', 'followup', 'proposal', 'closing', 'payment', 'delivery', 'aftersales')),\n  tags TEXT[] DEFAULT '{}',\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Proposals table\nCREATE TABLE IF NOT EXISTS proposals (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  lead_id UUID NOT NULL REFERENCES leads(id) ON DELETE CASCADE,\n  title TEXT NOT NULL,\n  description TEXT,\n  total_value DECIMAL(10, 2) NOT NULL,\n  status TEXT DEFAULT 'draft' CHECK (status IN ('draft', 'sent', 'approved', 'rejected')),\n  valid_until TIMESTAMP WITH TIME ZONE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Projects table\nCREATE TABLE IF NOT EXISTS projects (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  lead_id UUID REFERENCES leads(id) ON DELETE SET NULL,\n  proposal_id UUID REFERENCES proposals(id) ON DELETE SET NULL,\n  name TEXT NOT NULL,\n  description TEXT,\n  status TEXT DEFAULT 'planning' CHECK (status IN ('planning', 'in_progress', 'completed', 'on_hold', 'cancelled')),\n  progress INTEGER DEFAULT 0 CHECK (progress >= 0 AND progress <= 100),\n  start_date TIMESTAMP WITH TIME ZONE,\n  end_date TIMESTAMP WITH TIME ZONE,\n  team_members UUID[] DEFAULT '{}',\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Project tasks table\nCREATE TABLE IF NOT EXISTS project_tasks (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  project_id UUID NOT NULL REFERENCES projects(id) ON DELETE CASCADE,\n  title TEXT NOT NULL,\n  description TEXT,\n  status TEXT DEFAULT 'todo' CHECK (status IN ('todo', 'in_progress', 'done')),\n  assigned_to UUID REFERENCES profiles(id) ON DELETE SET NULL,\n  due_date TIMESTAMP WITH TIME ZONE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Tasks table\nCREATE TABLE IF NOT EXISTS tasks (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  title TEXT NOT NULL,\n  description TEXT,\n  status TEXT DEFAULT 'todo' CHECK (status IN ('todo', 'in_progress', 'done')),\n  priority TEXT DEFAULT 'medium' CHECK (priority IN ('low', 'medium', 'high')),\n  assigned_to UUID REFERENCES profiles(id) ON DELETE SET NULL,\n  due_date TIMESTAMP WITH TIME ZONE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Financial records table\nCREATE TABLE IF NOT EXISTS financial_records (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  type TEXT NOT NULL CHECK (type IN ('income', 'expense')),\n  description TEXT NOT NULL,\n  amount DECIMAL(10, 2) NOT NULL,\n  category TEXT NOT NULL,\n  related_to UUID,\n  payment_method TEXT,\n  status TEXT DEFAULT 'pending' CHECK (status IN ('pending', 'paid', 'overdue')),\n  due_date TIMESTAMP WITH TIME ZONE,\n  paid_date TIMESTAMP WITH TIME ZONE,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Calendar events table\nCREATE TABLE IF NOT EXISTS calendar_events (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  title TEXT NOT NULL,\n  description TEXT,\n  type TEXT DEFAULT 'meeting' CHECK (type IN ('meeting', 'delivery', 'follow_up', 'financial', 'other')),\n  start_date TIMESTAMP WITH TIME ZONE NOT NULL,\n  end_date TIMESTAMP WITH TIME ZONE,\n  related_to UUID,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Media library table\nCREATE TABLE IF NOT EXISTS media_items (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  name TEXT NOT NULL,\n  url TEXT NOT NULL,\n  type TEXT NOT NULL CHECK (type IN ('image', 'video', 'document')),\n  category TEXT,\n  uploaded_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Agency settings table\nCREATE TABLE IF NOT EXISTS agency_settings (\n  id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),\n  user_id UUID NOT NULL REFERENCES profiles(id) ON DELETE CASCADE,\n  agency_name TEXT,\n  agency_logo TEXT,\n  primary_color TEXT,\n  whatsapp TEXT,\n  instagram TEXT,\n  email TEXT,\n  created_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP,\n  updated_at TIMESTAMP WITH TIME ZONE DEFAULT CURRENT_TIMESTAMP\n);\n\n-- Create indexes for better query performance\nCREATE INDEX IF NOT EXISTS idx_leads_user_id ON leads(user_id);\nCREATE INDEX IF NOT EXISTS idx_leads_status ON leads(status);\nCREATE INDEX IF NOT EXISTS idx_proposals_user_id ON proposals(user_id);\nCREATE INDEX IF NOT EXISTS idx_proposals_lead_id ON proposals(lead_id);\nCREATE INDEX IF NOT EXISTS idx_proposals_status ON proposals(status);\nCREATE INDEX IF NOT EXISTS idx_projects_user_id ON projects(user_id);\nCREATE INDEX IF NOT EXISTS idx_projects_status ON projects(status);\nCREATE INDEX IF NOT EXISTS idx_tasks_user_id ON tasks(user_id);\nCREATE INDEX IF NOT EXISTS idx_tasks_status ON tasks(status);\nCREATE INDEX IF NOT EXISTS idx_financial_user_id ON financial_records(user_id);\nCREATE INDEX IF NOT EXISTS idx_calendar_user_id ON calendar_events(user_id);\n\n-- Enable Row Level Security (RLS)\nALTER TABLE profiles ENABLE ROW LEVEL SECURITY;\nALTER TABLE leads ENABLE ROW LEVEL SECURITY;\nALTER TABLE copies ENABLE ROW LEVEL SECURITY;\nALTER TABLE proposals ENABLE ROW LEVEL SECURITY;\nALTER TABLE projects ENABLE ROW LEVEL SECURITY;\nALTER TABLE tasks ENABLE ROW LEVEL SECURITY;\nALTER TABLE financial_records ENABLE ROW LEVEL SECURITY;\nALTER TABLE calendar_events ENABLE ROW LEVEL SECURITY;\nALTER TABLE media_items ENABLE ROW LEVEL SECURITY;\n\n-- RLS Policies for Profiles\nCREATE POLICY \"Users can view own profile\" ON profiles\n  FOR SELECT USING (auth.uid() = id);\n\nCREATE POLICY \"Users can update own profile\" ON profiles\n  FOR UPDATE USING (auth.uid() = id);\n\n-- RLS Policies for Leads\nCREATE POLICY \"Users can view own leads\" ON leads\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert leads\" ON leads\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can update own leads\" ON leads\n  FOR UPDATE USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own leads\" ON leads\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- RLS Policies for Proposals\nCREATE POLICY \"Users can view own proposals\" ON proposals\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert proposals\" ON proposals\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can update own proposals\" ON proposals\n  FOR UPDATE USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own proposals\" ON proposals\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- RLS Policies for Projects\nCREATE POLICY \"Users can view own projects\" ON projects\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert projects\" ON projects\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can update own projects\" ON projects\n  FOR UPDATE USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own projects\" ON projects\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- RLS Policies for Tasks\nCREATE POLICY \"Users can view own tasks\" ON tasks\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert tasks\" ON tasks\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can update own tasks\" ON tasks\n  FOR UPDATE USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own tasks\" ON tasks\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- RLS Policies for Financial Records\nCREATE POLICY \"Users can view own financial records\" ON financial_records\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert financial records\" ON financial_records\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can update own financial records\" ON financial_records\n  FOR UPDATE USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own financial records\" ON financial_records\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- RLS Policies for Calendar Events\nCREATE POLICY \"Users can view own calendar events\" ON calendar_events\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert calendar events\" ON calendar_events\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can update own calendar events\" ON calendar_events\n  FOR UPDATE USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own calendar events\" ON calendar_events\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- RLS Policies for Media Items\nCREATE POLICY \"Users can view own media\" ON media_items\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert media\" ON media_items\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own media\" ON media_items\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- RLS Policies for Copies\nCREATE POLICY \"Users can view own copies\" ON copies\n  FOR SELECT USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can insert copies\" ON copies\n  FOR INSERT WITH CHECK (auth.uid() = user_id);\n\nCREATE POLICY \"Users can update own copies\" ON copies\n  FOR UPDATE USING (auth.uid() = user_id);\n\nCREATE POLICY \"Users can delete own copies\" ON copies\n  FOR DELETE USING (auth.uid() = user_id);\n\n-- Insert sample niches\nINSERT INTO niches (name, description, icon) VALUES\n  ('Barbearia', 'Serviços de corte de cabelo e barba', '💈'),\n  ('Dentista', 'Clínica odontológica', '🦷'),\n  ('Advogado', 'Serviços jurídicos', '⚖️'),\n  ('Restaurante', 'Serviço de alimentação', '🍽️'),\n  ('Pizzaria', 'Pizzaria e delivery', '🍕'),\n  ('Clínica de Estética', 'Serviços de beleza', '💅'),\n  ('Salão', 'Salão de beleza', '💇'),\n  ('Academia', 'Academia de ginástica', '💪'),\n  ('Loja de Roupas', 'Vestuário e moda', '👕'),\n  ('Pet Shop', 'Cuidados para animais', '🐾'),\n  ('Oficina', 'Conserto de veículos', '🔧'),\n  ('Imobiliária', 'Venda e locação de imóveis', '🏠'),\n  ('Mercado', 'Supermercado', '🛒'),\n  ('Assistência Técnica', 'Conserto de eletrônicos', '📱'),\n  ('Contador', 'Serviços contábeis', '📊'),\n  ('Escola', 'Educação', '🎓'),\n  ('Psicólogo', 'Psicologia e terapia', '🧠'),\n  ('Lanchonete', 'Alimentos rápidos', '🍔'),\n  ('Microempresa', 'Diversos serviços', '🏢')\nON CONFLICT (name) DO NOTHING;\n\n-- Insert sample services\nINSERT INTO services (name, description, price, niche_id) VALUES\n  ('Landing Page Simples', 'Landing page básica com informações', 1500.00, (SELECT id FROM niches WHERE name = 'Microempresa' LIMIT 1)),\n  ('Landing Page Profissional', 'Landing page com design avançado', 2500.00, (SELECT id FROM niches WHERE name = 'Microempresa' LIMIT 1)),\n  ('Cardápio Digital', 'Cardápio interativo para restaurantes', 1000.00, (SELECT id FROM niches WHERE name = 'Restaurante' LIMIT 1)),\n  ('Cardápio com Pedido', 'Cardápio com integração de pedidos', 2000.00, (SELECT id FROM niches WHERE name = 'Pizzaria' LIMIT 1)),\n  ('Site de Agendamento', 'Sistema de agendamento online', 3000.00, (SELECT id FROM niches WHERE name = 'Barbearia' LIMIT 1)),\n  ('Catálogo Digital', 'Catálogo digital de produtos', 1500.00, (SELECT id FROM niches WHERE name = 'Loja de Roupas' LIMIT 1)),\n  ('Vitrine Online', 'Vitrine de produtos online', 2000.00, (SELECT id FROM niches WHERE name = 'Microempresa' LIMIT 1)),\n  ('CRM Simples', 'Sistema CRM básico', 3500.00, (SELECT id FROM niches WHERE name = 'Microempresa' LIMIT 1)),\n  ('Sistema Personalizado', 'Sistema customizado conforme necessidade', 5000.00, (SELECT id FROM niches WHERE name = 'Microempresa' LIMIT 1)),\n  ('Manutenção Mensal', 'Manutenção e suporte mensal', 500.00, (SELECT id FROM niches WHERE name = 'Microempresa' LIMIT 1))\nON CONFLICT DO NOTHING;\n